const items = $input.all();

// Filtrer ET mapper en une seule opération
const donnees = items
    .filter(item => {
        const ecart = item.json.Ecart_Global;
        return Math.abs(parseFloat(ecart)) <= 1;
    })
    .map(item => {
        const row = item.json;
        const facturefrs = row.FactureFrns?.startsWith("FN°") 
            ? row.FactureFrns 
            : "FN°" + (row.FactureFrns || "");

        return {
            Code: row.CODE_FRNS || "",
            DFF: row.N_Depot || "",
            FactureFrs: facturefrs,
            Date: row.DateFacture || "",
            BR: row.Bon_Reception || "",
            Nom: ""
        };
    });

return [{
    json: {
        donnees: JSON.stringify(donnees),  // ← stringify it here
        email_expediteur: "astitoumde@gmail.com",
        headless: false
    }
}];
